INSERT INTO departments (name, sector_id) SELECT 'إدارة تراخيص منسوبي الطيران', s.id FROM sectors s WHERE s.name='قطاع سلامة الطيران والاستدامة البيئية' AND NOT EXISTS (SELECT 1 FROM departments d WHERE d.name='إدارة تراخيص منسوبي الطيران' AND d.sector_id=s.id);
