-- 5. ربط الخدمات بالمنسقين (مرجع: ملف الإكسل الأصلي — يعمل حتى لو الخدمات موجودة مسبقاً)

-- ماجد حجازي (15 خدمة)
UPDATE services SET coordinator_id = (SELECT id FROM users WHERE username='mhejazi' LIMIT 1)
WHERE name IN (
  'خدمة شطب تسجيل طائرة',
  'خدمة شهادة تسجيل طائرة',
  'خدمة نقل ملكية طائرة',
  'خدمة حجز علامة تسجيل طائرة',
  'خدمة الحد الأدنى للفصل الرأسي المخفض – RVSM',
  'خدمة استخدام قائمة الحد الأدنى من المعداتMEL',
  'خدمة تمديد الفترة المجدولة لبرنامج الصيانة المعتمد',
  'خدمة رخصة مفتش مفوض',
  'خدمة تصريح طيران خاص',
  'خدمة رخصة فني اصلاح طائرات',
