-- تحقق
SELECT
  (SELECT COUNT(*) FROM users WHERE role='coordinator') AS منسقون,
  (SELECT COUNT(*) FROM sectors) AS قطاعات,
  (SELECT COUNT(*) FROM departments) AS ادارات,
  (SELECT COUNT(*) FROM services) AS خدمات,
  (SELECT COUNT(*) FROM services WHERE coordinator_id IS NULL) AS خدمات_بدون_منسق;